    cols = max(1, int(size ** 0.5))
    rows = max(1, size // cols)
    rects = []
    for r in range(rows):
        for c in range(cols):
            rects.append([c, r, c + 1, r + 1])
    rng.shuffle(rects)
    return [rects]

def gen(rng, size):
    cols = max(2, int(size ** 0.5))
    rows = max(2, size // cols)
    rects = []
    for r in range(rows):
        for c in range(cols):
            rects.append([c, r, c + 1, r + 1])
    if rng.random() < 0.7 and len(rects) > 1:
        rects.pop(rng.randrange(len(rects)))
    rng.shuffle(rects)
    return [rects]

