class Solution:
    def isRectangleCover(self, rectangles):
        # naive: paint a scaled grid only feasible for small coords; instead use
        # an independent area+overlap check via coordinate compression.
        xs = sorted(set([r[0] for r in rectangles] + [r[2] for r in rectangles]))
        ys = sorted(set([r[1] for r in rectangles] + [r[3] for r in rectangles]))
        xi = {x: i for i, x in enumerate(xs)}
        yi = {y: i for i, y in enumerate(ys)}
        grid = [[0] * (len(xs) - 1) for _ in range(len(ys) - 1)]
        for x1, y1, x2, y2 in rectangles:
            for a in range(xi[x1], xi[x2]):
                for b in range(yi[y1], yi[y2]):
                    grid[b][a] += 1
                    if grid[b][a] > 1:
                        return False
        minx, miny = xs[0], ys[0]
        maxx, maxy = xs[-1], ys[-1]
        for b in range(len(ys) - 1):
            for a in range(len(xs) - 1):
                if grid[b][a] == 0:
                    return False
        return True

