class Solution:
    def isRectangleCover(self, rectangles):
        area = 0
        corners = set()
        minx = miny = float('inf')
        maxx = maxy = float('-inf')
        for x1, y1, x2, y2 in rectangles:
            area += (x2 - x1) * (y2 - y1)
            minx = min(minx, x1); miny = min(miny, y1)
            maxx = max(maxx, x2); maxy = max(maxy, y2)
            for p in ((x1, y1), (x1, y2), (x2, y1), (x2, y2)):
                if p in corners:
                    corners.remove(p)
                else:
                    corners.add(p)
        expected = {(minx, miny), (minx, maxy), (maxx, miny), (maxx, maxy)}
        if corners != expected:
            return False
        return area == (maxx - minx) * (maxy - miny)

solutions.javascript:
var isRectangleCover = function(rectangles) {
    let area = 0;
    const corners = new Set();
    let minx = Infinity, miny = Infinity, maxx = -Infinity, maxy = -Infinity;
    const toggle = (x, y) => {
        const k = x + ',' + y;
        if (corners.has(k)) corners.delete(k); else corners.add(k);
    };
    for (const [x1, y1, x2, y2] of rectangles) {
        area += (x2 - x1) * (y2 - y1);
        minx = Math.min(minx, x1); miny = Math.min(miny, y1);
        maxx = Math.max(maxx, x2); maxy = Math.max(maxy, y2);
        toggle(x1, y1); toggle(x1, y2); toggle(x2, y1); toggle(x2, y2);
    }
    const expected = [[minx, miny], [minx, maxy], [maxx, miny], [maxx, maxy]];
    if (corners.size !== 4) return false;
    for (const [x, y] of expected) if (!corners.has(x + ',' + y)) return false;
    return area === (maxx - minx) * (maxy - miny);
};
